steps.script:
var d = tree.root.get_node_or_null("BombSquigsDialog")
if d == null:
	return "NO_DIALOG"
var btns = d.find_children("*", "Button", true, false)
var has_target = false
var has_decline = false
for b in btns:
	var t = String(b.text)
	if t.contains("Bomb Squigs"):
		has_target = true
	if t.contains("Decline"):
		has_decline = true
return has_target and has_decline

var d = tree.root.get_node_or_null("BombSquigsDialog")
if d == null:
	return "NO_DIALOG"
d._on_decline_pressed()
return true
